mapper.select:
select r.id rid, resource_name, resource_size, type_name from t_class_resource cr join t_resource r on cr.fk_resource_id = r.id left join t_resource_type rt on r.fk_resource_type_id = rt.id where
cr.fk_class_id = #{classId}
and r.resource_name = #{resourceName}
and rt.type_name = #{resourceTypeName}
and r.is_delete = 1 and rt.is_delete = 1

select r.id rid, resource_name, resource_size, resource_suffix, r.create_time r_create_time, type_name from t_resource r left join t_resource_type rt on r.fk_resource_type_id = rt.id where r.is_delete = 1 and rt.is_delete = 1
and resource_name like concat('%', #{name}, '%')
and resource_suffix like concat('%', #{type}, '%')
and r.create_time >= #{start}
and r.create_time <= #{end}

mapper.insert:
